import { useState, useContext } from "react";
import axios from "axios";
import Button from "react-bootstrap/Button";
import Form from "react-bootstrap/Form";
import "bootstrap/dist/css/bootstrap.min.css";
import UserContext from './context';

export default function Deposit() {
  const [deposit, setDeposit] = useState("");
  const [pin, setPin] = useState("");
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMessage, setErrorMessage] = useState("");
  const { user, setUser } = useContext(UserContext);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMessage("");
    setSuccessMessage("");

    const depositAmount = parseFloat(deposit);

    if (isNaN(depositAmount) || depositAmount <= 0) {
      setErrorMessage("Invalid deposit amount.");
      return;
    }

    if (pin.length !== 4) {
      setErrorMessage("Transaction PIN must be 4 digits.");
      return;
    }

    try {
      const response = await axios.post("http://localhost:8080/api/users/deposit", {
        amount: depositAmount,
        pin: pin
      });

      setSuccessMessage(`Successfully deposited ₹${depositAmount}. New balance: ₹${response.data.newBalance}`);
      setUser({ ...user, amount: response.data.newBalance, transactions: response.data.transactions });
      setDeposit("");
      setPin("");
    } catch (error) {
      setErrorMessage(error.response?.data?.message || "Deposit failed. Please try again.");
    }
  };

  if (!user) return <div className="container mt-5"><h3>Please login to deposit money.</h3></div>;

  return (
    <div className="background">
      <h1 className="register-heading">Deposit</h1>
      <div className="text-center mb-4">
        <h4>Current Balance: ₹{user.amount}</h4>
      </div>

      {successMessage && <div className="alert alert-success">{successMessage}</div>}
      {errorMessage && <div className="alert alert-danger">{errorMessage}</div>}

      <Form className="custom-form" onSubmit={handleSubmit}>
        <Form.Group className="mb-3 custom-form-group">
          <Form.Label className="custom-label">Amount</Form.Label>
          <Form.Control
            className="custom-input"
            type="number"
            placeholder="Enter deposit amount"
            value={deposit}
            onChange={(e) => setDeposit(e.target.value)}
          />
        </Form.Group>

        <Form.Group className="mb-3 custom-form-group">
          <Form.Label className="custom-label">Transaction PIN</Form.Label>
          <Form.Control
            className="custom-input"
            type="password"
            maxLength="4"
            placeholder="Enter 4-digit PIN"
            value={pin}
            onChange={(e) => setPin(e.target.value)}
          />
        </Form.Group>

        <Button className="custom-button" variant="primary" type="submit" disabled={!deposit || pin.length !== 4}>
          Deposit
        </Button>
      </Form>
    </div>
  );
}
